import React, { useState } from 'react';
import { toast } from 'react-toastify';
import { FaReply, FaTimes } from 'react-icons/fa';

const CommentForm = ({ onAddComment, replyingTo, onCancelReply }) => {
  const [comment, setComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!comment.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }
    
    try {
      setIsSubmitting(true);
      await onAddComment(comment);
      setComment('');
    } catch (error) {
      console.error('Error submitting comment:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white dark:bg-gray-700 rounded-lg p-4 shadow-sm">
      {replyingTo && (
        <div className="flex items-center justify-between mb-2 bg-blue-50 dark:bg-blue-900 p-2 rounded">
          <div className="flex items-center text-sm text-blue-600 dark:text-blue-300">
            <FaReply className="mr-1" />
            <span>Replying to {replyingTo}</span>
          </div>
          <button 
            type="button" 
            onClick={onCancelReply}
            className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300"
          >
            <FaTimes />
          </button>
        </div>
      )}
      
      <div className="flex flex-col">
        <textarea
          className="w-full px-3 py-2 text-gray-700 dark:text-gray-200 border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
          rows="3"
          placeholder="Add a comment..."
          value={comment}
          onChange={(e) => setComment(e.target.value)}
          disabled={isSubmitting}
        ></textarea>
        
        <div className="flex justify-end mt-2">
          <button
            type="submit"
            disabled={isSubmitting}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50 transition-colors duration-200"
          >
            {isSubmitting ? 'Submitting...' : 'Submit Comment'}
          </button>
        </div>
      </div>
    </form>
  );
};

export default CommentForm;
